from dataclasses import dataclass
from datetime import date, timedelta
from typing import Optional

@dataclass
class SAConsultationRecord:
    dpia_id: str
    sa_name: str           # e.g. "ICO", "CNIL", "BfDI"
    submitted_date: date
    high_risk_description: str   # specific risk requiring consultation
    sa_reference_number: Optional[str] = None
    standard_response_deadline: date = None
    extended_deadline: Optional[date] = None
    sa_response_received: Optional[date] = None
    sa_outcome: Optional[str] = None   # "no_objection", "conditions", "prohibition"

    def __post_init__(self):
        if self.standard_response_deadline is None:
            self.standard_response_deadline = self.submitted_date + timedelta(weeks=8)

    def max_deadline(self) -> date:
        if self.extended_deadline:
            return self.extended_deadline
        return self.standard_response_deadline

    def is_overdue(self, today: date) -> bool:
        return today > self.max_deadline() and self.sa_response_received is None

    def feature_may_launch(self) -> bool:
        return self.sa_outcome == "no_objection"

    def status(self, today: date) -> str:
        if self.sa_outcome:
            return f"SA responded: {self.sa_outcome}"
        if self.is_overdue(today):
            return "SA response overdue — contact SA for status"
        days_left = (self.max_deadline() - today).days
        return f"Awaiting SA response — {days_left} days remaining"
